{
  "name": "Weatherization Referral and Packaging Program (WRAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Households with incomes at or below 60% of New York State median income (SMI), aligned with HEAP income guidelines. Automatic eligibility if a household member receives SSI, Public Assistance, SNAP, or HEAP benefits. Specific dollar amounts vary annually by household size and are not listed in sources; families must check current HEAP guidelines via OTDA or local providers[1][5][8].",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Low-income homeowners and renters (renters in some regions like Nassau County via WRAP); priority for seniors, families with children, and persons with disabilities[1][5][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Weatherization services including air sealing (weather stripping, caulking), attic and wall insulation, heating system improvements or replacement, lighting efficiency upgrades, hot water tank and pipe insulation, refrigerator replacements with Energy Star units. WRAP specifically includes energy audits to address social, health, or safety issues such as insulation, caulking windows/doors, window repair, door replacement, heating system repair, pipe/water heater wrapping. Average energy savings exceed 20%. Up to $6,500 per unit maximum in some contexts, with typical construction $3,000-$4,000[1][3][5][8].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local provider (e.g., for Nassau County via EAC Network as part of HEAP/WRAP; Chautauqua County: Chautauqua Opportunities, Inc. at 716-661-9430[5][8]", "List of statewide providers via https://otda.ny.gov/workingfamilies/wap.asp[1]", "HCR site for more info: https://hcr.ny.gov/weatherization[6]"],
    "processing_time": "Not specified; involves application submission, eligibility confirmation when funding available, energy audit, work installation, and final inspection[1].",
    "waitlist": "Funding-dependent; local provider contacts when funds available[1].",
    "forms": ["Application submitted to local service provider; no specific form name/number listed[1]"],
    "documents": ["Proof of income, HEAP/SSI/SNAP/Public Assistance benefits if claiming automatic eligibility; details confirmed during interview and audit[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered statewide by NYS HCR through local subgrantee agencies; some regional renter restrictions (e.g., NYC individual renters cannot apply[2]); WRAP noted in Nassau County via EAC Network[8].",
    "regional_variations": "Local providers vary by county/region (e.g., Chautauqua Opportunities in Chautauqua County, Margert in some areas, EAC Network in Nassau); different contact points and potential wait times/funding availability[1][4][5][8].",
    "offices_or_providers": ["Local NYS WAP providers listed via OTDA/HCR sites; examples: Chautauqua Opportunities, Inc. (716-661-9430), EAC Network (Nassau)[1][5][8]"]
  },
  "official_source": "https://otda.ny.gov/workingfamilies/wap.asp",
  "gotchas": ["WRAP is a referral/packaging component often bundled with HEAP, not standalone; priority groups (seniors, children, disabled) get preference but no guaranteed age cutoff; renters eligible statewide but NYC excludes individual renters (homeowners/building owners only); must contact local provider as no central application; buildings weatherized after 1994 ineligible for repeat; owner may need 25% match for multi-family (waivers possible)[1][2][3][8]", "Income tied to HEAP guidelines, which change yearly—verify current levels."],
  "data_shape_notes": "Referral and packaging tied to local HEAP/WAP delivery; priority-based with automatic eligibility via benefits receipt; local subgrantees handle delivery with regional providers; no fixed dollar benefits per household, services determined by energy audit."
}

{
  "name": "State Health Insurance Assistance Program (SHIP) / Health Insurance Information, Counseling and Assistance Program (HIICAP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits, asset limits, or financial requirements. Open to all Medicare beneficiaries and New York residents who will soon become Medicare eligible (typically age 65 or qualifying under 65 via SSDI for 24 months or ALS).[1][2]",
    "asset_limits": "No asset limits or tests apply. No specification of countable or exempt assets.",
    "other_requirements": ["Must be a Medicare beneficiary or soon-to-be eligible New York resident (includes U.S. citizens or legal permanent residents for at least five years if not SSDI-eligible).[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential, unbiased one-on-one counseling and assistance on Medicare benefits/options/paperwork, Medicare Advantage, Medigap, Part D prescription plans, costs/deductibles, low-income programs (e.g., EPIC, Medicare Savings Programs, Extra Help), health insurance problem resolution, claims filing, and referrals. Provided by nearly 500 trained counselors statewide; no fixed hours, dollar amounts, or limits specified.[1][4][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free hotline 1-800-701-0501 (routed to local county HIICAP office); In-person: Schedule appointment via local Area Agency on Aging (AAA) office; Website: https://aging.ny.gov/health-insurance-information-counseling-and-assistance-programs (for info and local contacts); NYC-specific: 212-AGING-NYC (212-244-6469).[1][2][3]"],
    "processing_time": "Immediate phone routing and counseling scheduling; no formal application processing time as it's not an enrollment program.",
    "waitlist": null,
    "forms": ["No specific forms required for counseling; simple volunteer application if interested in volunteering.[1][8]"],
    "documents": ["No documents needed for initial counseling; may request Medicare card, insurance details, or income info for specific advice (e.g., low-income programs).[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available to New York state residents only.",
    "regional_variations": "Delivered through 59 local Area Agencies on Aging (AAAs) or subcontractors with nearly 500 counselors; services uniform but accessed via county-specific offices (call routed by county); potential minor differences in local providers or NYC-specific hotline.[1][6]",
    "offices_or_providers": ["Headquartered at NYS Office for the Aging, Two Empire State Plaza, Albany NY 12223; local via 59 AAAs.[1][5]"]
  },
  "official_source": "https://aging.ny.gov/health-insurance-information-counseling-and-assistance-programs",
  "gotchas": ["Not a financial aid or healthcare provider program—only free counseling/info, no direct payments or coverage; people confuse it with income-based aid like EPIC (which has limits: e.g., $35k single/$50k couple for some discounts); must be/will be Medicare-eligible (not general health insurance help); services via local AAA, not centralized.[1][4][7]"],
  "data_shape_notes": "no income/asset test; counseling-only service via statewide AAA network; open to pre-Medicare eligible NY residents; county-routed access."
}

{
  "name": "Legal Services for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict statewide income limits; many programs (especially Title III-B funded) do not condition services on income or resources. Some providers require low-income status (e.g., ~125% of Federal Poverty Guidelines) unless referred by local Office for Aging. Encouraged for low-income, subsistence income, or threatened loss of income, but exact dollar amounts vary by provider and are not universally applied.[1][2][3][4][5]",
    "asset_limits": "Generally no asset limits; financial eligibility often not required, particularly for Title III-B programs. Low resources considered for some providers.[2][3][5]",
    "other_requirements": ["NY resident (specific counties/boroughs depending on provider)", "Low-income or inability to afford private legal help (priority, not always required)", "Nursing home/assisted living resident, chronic health issues, homelessness risk, limited English, guardianship, abuse/neglect/exploitation victim, physical isolation[1][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free or low-cost civil legal advice, counseling, representation, and referrals on issues including: Social Security/SSI, Food Stamps, pensions, HEAP, tenant issues, home repair fraud, Medicare/Medicaid, nursing home/adult home issues, abuse/financial exploitation, ADA, grandparents’ rights, consumer issues, wills/estate planning, health care proxies, powers of attorney, housing, public benefits applications/appeals, evictions, patients’ rights. Provided in client's language; pro bono attorneys for some.[1][2][4][5][7]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Office for the Aging or provider: e.g., Aging Connect at 212-AGING-NYC (212-244-6469) for NYC[4]", "Legal Aid Society of Mid-NY (Central NY counties)[2]", "Dutchess County Office for the Aging: 845-486-2555 or 866-486-2555[5]", "Legal Services of the Hudson Valley: 845-471-0058[5]", "VOLS Senior Law Project (NYC)[7]", "Use NYC Aging’s Find Services locator for legal services[4]", "Local providers vary by county (e.g., lasnny.org for Albany[1])"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["No specific statewide form; provider-specific intake"],
    "documents": ["Proof of age (ID), residency, income/resources if required by provider, details of legal issue (e.g., benefit denial letters, eviction notices). Financial info only if needed for eligibility determination.[3]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "County/borough-specific providers; e.g., Albany County[1], 13 Central NY counties[2], all 5 NYC boroughs[4], Dutchess County[5]",
    "regional_variations": "Eligibility stricter in some areas (income test unless OFA referral); different providers, attorneys, focus areas; no financial eligibility in many (e.g., Dutchess[5], Title III-B[3]). NYC via DFTA contractors; upstate via local OFAs.[1][2][4][5]",
    "offices_or_providers": ["Legal Aid Society of Northeastern NY (Albany)[1]", "Legal Aid Society of Mid-NY (Central NY)[2]", "NYC Aging contractors (all boroughs)[4]", "Paul I. Weinberger/Dutchess OFA[5]", "VOLS (NYC)[7]"]
  },
  "official_source": "https://aging.ny.gov/legal-services-initiative",
  "gotchas": ["Not a single statewide program—must contact local Office for Aging or provider for your county; some require low-income unless referred; voluntary contributions may be suggested (e.g., $10 consultation) but do not affect eligibility; focuses on civil matters only, not criminal; Title III-B funded services cannot deny based on income[1][3][4]"],
  "data_shape_notes": "Decentralized by county/region with local providers; no uniform income/asset tests (many none); priority for vulnerable seniors; varies significantly by location"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; program is free and open to all qualifying residents regardless of financial status.",
    "asset_limits": "No asset limits or tests apply.",
    "other_requirements": ["Must reside (or be considering placement) in a long-term care facility such as nursing homes, assisted living, adult care facilities, family-type homes, or board and care homes in New York.", "Open to residents, family members, friends, facility staff, or anyone concerned about a resident's welfare.", "People with disabilities are included, not limited to elderly."][1][2][3][4][5]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy to resolve complaints, mediation between residents/families/staff, education on rights and long-term care issues, referral to agencies like NY Department of Health if needed; volunteer ombudsmen visit facilities 2-4 hours/week on average; promotes dignity, quality of life, and resident rights; covers issues like care, abuse/neglect, food, finances, policies.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Statewide toll-free phone: 1-855-582-6769[1]", "Regional examples: CIDNY (NYC area) 888-855-9807 or ltcop@cidny.org[2]", "Western NY (Erie/Niagara/Chautauqua/Cattaraugus): 716-817-9222 or 844-527-5509[4]", "Southern Tier (Broome/Chenango/Delaware/Tioga): 607-722-1251[5]", "Oneida County: Contact local office[6]", "Call regional coordinator via state line or visit aging.ny.gov for local contacts; no formal application form, intake by phone."],
    "processing_time": "Immediate assistance upon contact; no formal processing as it's complaint-based advocacy, not enrollment.",
    "waitlist": null,
    "forms": ["No specific forms required; confidential intake by phone or email."],
    "documents": ["None required; provide facility name, resident details, and complaint description verbally or via email."][1][2][3]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available throughout New York State for residents of licensed long-term care facilities.",
    "regional_variations": "Administered regionally by non-profits, independent living centers, or area agencies on aging under state supervision; different local sponsors, phone numbers, and coordinators (e.g., CIDNY in NYC, People Inc. in Western NY, Action for Older Persons in Southern Tier); volunteer coverage may vary by facility assignment.",
    "offices_or_providers": ["State Ombudsman office supervises; regional examples: CIDNY, People Inc. (Buffalo), Action for Older Persons (Broome area), Oneida County Office for Aging."][1][2][4][5][6]
  },
  "official_source": "https://aging.ny.gov/long-term-care-ombudsman-program",
  "gotchas": ["Not a direct service provider (e.g., no healthcare or financial aid); focuses on advocacy and complaint resolution only.", "Requires resident permission to act on complaints due to strict confidentiality.", "Primarily volunteer-driven, so availability depends on local ombudsman schedules and facility assignments.", "Open to non-residents like families pre-placement, but must relate to NY long-term care facilities.", "Not limited to seniors—includes people with disabilities of any age."][1][2][3],
  "data_shape_notes": "no income/asset test; advocacy-only (not financial/services); regionally administered with local contacts; volunteer-based, complaint-driven (no enrollment/waitlist); covers residents + families/friends pre-placement."
}

